package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyQuotaController enforces per-namespace limits on the number of
// CiliumNetworkPolicy resources to prevent policy sprawl in multi-tenant clusters.
type PolicyQuotaController struct {
	log                   logrus.FieldLogger
	cnpResource           resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	maxPerNamespace       int
	namespacePolicyCounts map[string]int
	mu                    sync.RWMutex
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
// maxPerNamespace specifies the maximum number of CiliumNetworkPolicy resources
// allowed per namespace. A value of 0 means unlimited.
func NewPolicyQuotaController(
	logger logrus.FieldLogger,
	cnpResource resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   logger,
		cnpResource:           cnpResource,
		maxPerNamespace:       maxPerNamespace,
		namespacePolicyCounts: make(map[string]int),
	}
}

// CheckQuota checks whether creating a new policy in the given namespace
// would exceed the per-namespace quota. Returns an error if quota would be exceeded.
func (p *PolicyQuotaController) CheckQuota(namespace string) error {
	if p.maxPerNamespace == 0 {
		return nil // Unlimited quota
	}

	p.mu.RLock()
	currentCount := p.namespacePolicyCounts[namespace]
	p.mu.RUnlock()

	if currentCount >= p.maxPerNamespace {
		return fmt.Errorf(
			"policy quota exceeded for namespace %s: current %d, max %d",
			namespace, currentCount, p.maxPerNamespace,
		)
	}
	return nil
}

// Run starts the policy quota controller loop. It watches CiliumNetworkPolicy
// resources and maintains per-namespace counts to enforce quotas.
func (p *PolicyQuotaController) Run(ctx context.Context) error {
	p.log.Info("Starting PolicyQuotaController")

	events := p.cnpResource.Events(ctx)
	for {
		select {
		case <-ctx.Done():
			p.log.Info("PolicyQuotaController stopped")
			return ctx.Err()
		case event, ok := <-events:
			if !ok {
				p.log.Info("PolicyQuotaController event channel closed")
				return nil
			}

			var err error
			switch event.Kind {
			case resource.Sync:
				p.log.Debug("PolicyQuotaController synced with API server")
				event.Done(nil)
				continue

			case resource.Upsert:
				err = p.handlePolicyUpsert(event.Object)

			case resource.Delete:
				err = p.handlePolicyDelete(event.Object)
			}

			event.Done(err)
		}
	}
}

// handlePolicyUpsert handles the addition or update of a CiliumNetworkPolicy.
func (p *PolicyQuotaController) handlePolicyUpsert(cnp *cilium_v2.CiliumNetworkPolicy) error {
	namespace := cnp.GetNamespace()

	p.mu.Lock()
	defer p.mu.Unlock()

	p.log.WithFields(logrus.Fields{
		logfields.K8sNamespace:            namespace,
		logfields.CiliumNetworkPolicyName: cnp.GetName(),
	}).Debug("Handling policy upsert")

	p.namespacePolicyCounts[namespace]++
	return nil
}

// handlePolicyDelete handles the deletion of a CiliumNetworkPolicy.
func (p *PolicyQuotaController) handlePolicyDelete(cnp *cilium_v2.CiliumNetworkPolicy) error {
	namespace := cnp.GetNamespace()

	p.mu.Lock()
	defer p.mu.Unlock()

	p.log.WithFields(logrus.Fields{
		logfields.K8sNamespace:            namespace,
		logfields.CiliumNetworkPolicyName: cnp.GetName(),
	}).Debug("Handling policy delete")

	count := p.namespacePolicyCounts[namespace]
	if count > 0 {
		p.namespacePolicyCounts[namespace]--
	}

	// Clean up empty entries
	if p.namespacePolicyCounts[namespace] == 0 {
		delete(p.namespacePolicyCounts, namespace)
	}

	return nil
}

// GetNamespacePolicyCounts returns a copy of the current per-namespace policy counts.
// This is useful for testing and monitoring.
func (p *PolicyQuotaController) GetNamespacePolicyCounts() map[string]int {
	p.mu.RLock()
	defer p.mu.RUnlock()

	counts := make(map[string]int)
	for k, v := range p.namespacePolicyCounts {
		counts[k] = v
	}
	return counts
}

