package quota

import (
	"context"
	"fmt"
	"sync"
	"testing"
	"time"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/assert"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/policy/api"
)

// mockCNPResource is a mock implementation of resource.Resource for testing.
type mockCNPResource struct {
	events chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func (m *mockCNPResource) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	// In a real implementation, these would be properly closed.
	// For testing, we just return the channel.
	return m.events
}

func (m *mockCNPResource) Store(ctx context.Context) (resource.Store[*cilium_v2.CiliumNetworkPolicy], error) {
	return nil, fmt.Errorf("not implemented in mock")
}

// TestCheckQuota tests the CheckQuota method.
func TestCheckQuota(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	entry := logrus.NewEntry(logger)

	controller := NewPolicyQuotaController(entry, nil, 2)

	// Simulate adding policies
	controller.mu.Lock()
	controller.namespacePolicyCounts["ns1"] = 1
	controller.namespacePolicyCounts["ns2"] = 2
	controller.mu.Unlock()

	tests := []struct {
		name      string
		namespace string
		shouldErr bool
		errMsg    string
	}{
		{
			name:      "namespace with room",
			namespace: "ns1",
			shouldErr: false,
		},
		{
			name:      "namespace at quota",
			namespace: "ns2",
			shouldErr: true,
			errMsg:    "policy quota exceeded",
		},
		{
			name:      "empty namespace",
			namespace: "ns3",
			shouldErr: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := controller.CheckQuota(tt.namespace)
			if tt.shouldErr {
				assert.Error(t, err)
				assert.Contains(t, err.Error(), tt.errMsg)
			} else {
				assert.NoError(t, err)
			}
		})
	}
}

// TestCheckQuotaUnlimited tests CheckQuota with unlimited quota.
func TestCheckQuotaUnlimited(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	entry := logrus.NewEntry(logger)

	// maxPerNamespace = 0 means unlimited
	controller := NewPolicyQuotaController(entry, nil, 0)

	controller.mu.Lock()
	controller.namespacePolicyCounts["ns1"] = 1000000
	controller.mu.Unlock()

	// Should not error even with very high count
	err := controller.CheckQuota("ns1")
	assert.NoError(t, err)
}

// TestHandlePolicyUpsert tests the handlePolicyUpsert method.
func TestHandlePolicyUpsert(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	entry := logrus.NewEntry(logger)

	controller := NewPolicyQuotaController(entry, nil, 5)

	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}

	err := controller.handlePolicyUpsert(cnp)
	assert.NoError(t, err)

	counts := controller.GetNamespacePolicyCounts()
	assert.Equal(t, 1, counts["test-ns"])

	// Add another policy to the same namespace
	err = controller.handlePolicyUpsert(cnp)
	assert.NoError(t, err)

	counts = controller.GetNamespacePolicyCounts()
	assert.Equal(t, 2, counts["test-ns"])
}

// TestHandlePolicyDelete tests the handlePolicyDelete method.
func TestHandlePolicyDelete(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	entry := logrus.NewEntry(logger)

	controller := NewPolicyQuotaController(entry, nil, 5)

	// Set up initial state
	controller.mu.Lock()
	controller.namespacePolicyCounts["test-ns"] = 2
	controller.mu.Unlock()

	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}

	err := controller.handlePolicyDelete(cnp)
	assert.NoError(t, err)

	counts := controller.GetNamespacePolicyCounts()
	assert.Equal(t, 1, counts["test-ns"])

	// Delete another
	err = controller.handlePolicyDelete(cnp)
	assert.NoError(t, err)

	counts = controller.GetNamespacePolicyCounts()
	// Namespace should be removed from map when count reaches 0
	_, exists := counts["test-ns"]
	assert.False(t, exists)
}

// TestHandlePolicyDeleteBelowZero tests that handlePolicyDelete doesn't go below 0.
func TestHandlePolicyDeleteBelowZero(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	entry := logrus.NewEntry(logger)

	controller := NewPolicyQuotaController(entry, nil, 5)

	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "test-ns",
		},
	}

	// Try to delete from empty namespace
	err := controller.handlePolicyDelete(cnp)
	assert.NoError(t, err)

	counts := controller.GetNamespacePolicyCounts()
	// Should not have the namespace in the map
	_, exists := counts["test-ns"]
	assert.False(t, exists)
}

// TestRunController tests the Run method with event simulation.
func TestRunController(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	entry := logrus.NewEntry(logger)

	// Create mock resource
	mockResource := &mockCNPResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 10),
	}

	controller := NewPolicyQuotaController(entry, mockResource, 5)

	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	// Run controller in a goroutine
	var wg sync.WaitGroup
	wg.Add(1)
	go func() {
		defer wg.Done()
		err := controller.Run(ctx)
		// Expect context cancellation error
		assert.Error(t, err)
	}()

	// Send some events
	cnp1 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy1",
			Namespace: "ns1",
		},
	}

	cnp2 := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy2",
			Namespace: "ns1",
		},
	}

	// Create a simple mock event
	mockEvent := &testEvent[*cilium_v2.CiliumNetworkPolicy]{
		kind:   resource.Upsert,
		object: cnp1,
	}

	mockResource.events <- mockEvent

	mockEvent2 := &testEvent[*cilium_v2.CiliumNetworkPolicy]{
		kind:   resource.Upsert,
		object: cnp2,
	}

	mockResource.events <- mockEvent2

	syncEvent := &testEvent[*cilium_v2.CiliumNetworkPolicy]{
		kind: resource.Sync,
	}

	mockResource.events <- syncEvent

	deleteEvent := &testEvent[*cilium_v2.CiliumNetworkPolicy]{
		kind:   resource.Delete,
		object: cnp1,
	}

	mockResource.events <- deleteEvent

	// Wait for context timeout to stop the controller
	wg.Wait()

	// Verify final state
	counts := controller.GetNamespacePolicyCounts()
	assert.Equal(t, 1, counts["ns1"]) // Only cnp2 should remain
}

// TestConcurrentAccess tests concurrent access to the controller.
func TestConcurrentAccess(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	entry := logrus.NewEntry(logger)

	controller := NewPolicyQuotaController(entry, nil, 100)

	// Simulate concurrent upserts and quota checks
	var wg sync.WaitGroup
	numGoroutines := 10
	policyPerGoroutine := 5

	for g := 0; g < numGoroutines; g++ {
		wg.Add(1)
		go func(goroutineNum int) {
			defer wg.Done()
			namespace := fmt.Sprintf("ns%d", goroutineNum%3) // Distribute across 3 namespaces

			for i := 0; i < policyPerGoroutine; i++ {
				cnp := &cilium_v2.CiliumNetworkPolicy{
					ObjectMeta: metav1.ObjectMeta{
						Name:      fmt.Sprintf("policy-%d-%d", goroutineNum, i),
						Namespace: namespace,
					},
				}

				err := controller.handlePolicyUpsert(cnp)
				assert.NoError(t, err)

				// Check quota
				err = controller.CheckQuota(namespace)
				if err != nil {
					t.Logf("Quota exceeded for %s: %v", namespace, err)
				}
			}
		}(g)
	}

	wg.Wait()

	// Verify counts
	counts := controller.GetNamespacePolicyCounts()

	// We expect 3 namespaces with policies
	assert.Len(t, counts, 3)

	// Each namespace should have about numGoroutines * policyPerGoroutine / 3 policies
	expectedPerNS := (numGoroutines * policyPerGoroutine) / 3
	for ns, count := range counts {
		assert.Equal(t, expectedPerNS, count, "namespace %s should have %d policies", ns, expectedPerNS)
	}
}

// testEvent is a simple test implementation of resource.Event.
type testEvent[T interface{}] struct {
	kind   resource.EventKind
	object T
}

func (e *testEvent[T]) Kind() resource.EventKind {
	return e.kind
}

func (e *testEvent[T]) Object() T {
	return e.object
}

func (e *testEvent[T]) Key() resource.Key {
	return resource.Key{}
}

func (e *testEvent[T]) Done(err error) {
	// No-op for testing
}

// TestQuotaExceeded tests the scenario where quota is exceeded.
func TestQuotaExceeded(t *testing.T) {
	logger := logrus.New()
	logger.SetLevel(logrus.DebugLevel)
	entry := logrus.NewEntry(logger)

	maxQuota := 3
	controller := NewPolicyQuotaController(entry, nil, maxQuota)

	// Add policies up to the limit
	for i := 0; i < maxQuota; i++ {
		cnp := &cilium_v2.CiliumNetworkPolicy{
			ObjectMeta: metav1.ObjectMeta{
				Name:      fmt.Sprintf("policy-%d", i),
				Namespace: "test-ns",
			},
		}
		err := controller.handlePolicyUpsert(cnp)
		assert.NoError(t, err)

		// Should not exceed quota yet
		err = controller.CheckQuota("test-ns")
		assert.NoError(t, err)
	}

	// Now adding one more should indicate quota exceeded
	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-overflow",
			Namespace: "test-ns",
		},
	}

	err := controller.handlePolicyUpsert(cnp)
	assert.NoError(t, err) // The upsert itself doesn't fail

	// But checking quota should fail
	err = controller.CheckQuota("test-ns")
	assert.Error(t, err)
	assert.Contains(t, err.Error(), "policy quota exceeded")
}

