	controller := NewPolicyQuotaController(entry, nil, 100)

	// Simulate concurrent upserts and quota checks
	var wg sync.WaitGroup
	numGoroutines := 10
	policyPerGoroutine := 5

	for g := 0; g < numGoroutines; g++ {
		wg.Add(1)
		go func(goroutineNum int) {
			defer wg.Done()
			namespace := fmt.Sprintf("ns%d", goroutineNum%3) // Distribute across 3 namespaces

			for i := 0; i < policyPerGoroutine; i++ {
				cnp := &cilium_v2.CiliumNetworkPolicy{
