		assert.NoError(t, err)

		// Should not exceed quota yet
		err = controller.CheckQuota("test-ns")
		assert.NoError(t, err)
	}

	// Now adding one more should indicate quota exceeded
	cnp := &cilium_v2.CiliumNetworkPolicy{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "policy-overflow",
			Namespace: "test-ns",
		},
